import pika

connection = pika.BlockingConnection(pika.ConnectionParameters('localhost', 5672, '/', credentials=pika.PlainCredentials('guest', 'guest')))
channel = connection.channel()

# Declare the queue that we will be publishing to (if it doesn’t exist already) and declare its type of exchange which is direct in this case – because our messages are sent directly, not via a fanout or topic pattern
channel.queue_declare(queue='task_queue', durable=True) # Declare the queue that we will be publishing to (if it doesn’t exist already). The second parameter 'durable': True means if RabbitMQ restarts then this message won‘t go away, so long live our producer.
channel.exchange_declare(exchange='direct_logs', exchange_type='direct') # Declare the direct log exchanges that we will be publishing to (if it doesn’t exist already) and declare its type of exchange which is 'direct'. ‘durable': True means if RabbitMQ restarts then this message won'\t go away, so long live our producer.
channel.basic_publish(exchange='direct_logs', routing_key='error', body='This task failed!') # Publishing the log to direct logs exchange with 'routing key': error (the queue name), and a message of ‘body’: This is an example text.
connection.close()   # Close connection after use, otherwise it will remain open in background until program ends or RabbitMQ server restarts which are not desirable for our scenario as we want to send messages only once at the end (after running a script). ‘credentials’: Credential pair used by pika.